import { motion } from "framer-motion";

const countries = [
  { name: "USA", role: "King", strategy: "Maintain Dollar, NATO dominance, contain China and Russia", status: "Global Hegemon" },
  { name: "China", role: "King", strategy: "Expand economic influence, build parallel global order, delay conflict", status: "Rising Superpower" },
  { name: "Russia", role: "Queen", strategy: "Break Western dominance, maintain buffer zones, asymmetric warfare", status: "Aggressive Player" },
  { name: "EU", role: "Queen", strategy: "Balance energy needs with loyalty to NATO, internal division", status: "Fragmented Ally" },
  { name: "India", role: "Knight", strategy: "Non-aligned, strategic autonomy, economic expansion", status: "Swing Player" },
  { name: "Turkey", role: "Knight", strategy: "Play both sides, regional expansion, leverage NATO", status: "Unpredictable" },
  { name: "Iran", role: "Bishop", strategy: "Proxy influence, oppose Israel and US dominance", status: "Ideological Player" },
  { name: "UK", role: "Bishop", strategy: "Support US, global finance influence", status: "Trusted Ally" },
  { name: "Germany", role: "Bishop", strategy: "Industrial base, energy vulnerable, EU anchor", status: "Strategic Economic Power" },
  { name: "France", role: "Bishop", strategy: "Push EU independence, balance diplomacy", status: "Diplomatic Player" },
  { name: "Africa", role: "Pawn", strategy: "Leverage natural resources, seek partnerships", status: "Resource Frontier" },
  { name: "Latin America", role: "Pawn", strategy: "Balance China/US influence, social unrest", status: "Contested Region" },
  { name: "Southeast Asia", role: "Pawn", strategy: "Caught in US-China struggle, strategic chokepoints", status: "Geo-strategic Zone" },
];

export default function GeopoliticalChessboard() {
  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px', padding: '20px' }}>
      {countries.map((country, index) => (
        <motion.div
          key={index}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: index * 0.1 }}
          style={{ background: '#f9f9f9', borderRadius: '16px', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', padding: '16px' }}
        >
          <h2 style={{ fontSize: '20px', fontWeight: 'bold', marginBottom: '8px' }}>{country.name}</h2>
          <p style={{ fontSize: '14px', color: '#555', marginBottom: '4px' }}><strong>Role:</strong> {country.role}</p>
          <p style={{ fontSize: '14px', color: '#666', marginBottom: '8px' }}><strong>Strategy:</strong> {country.strategy}</p>
          <p style={{ fontSize: '12px', color: '#999', fontStyle: 'italic' }}><strong>Status:</strong> {country.status}</p>
        </motion.div>
      ))}
    </div>
  );
}
